// NocoDB v2: { list: [ { order_nr, product, asset, qty, customer, priority, due_date, status } ] }
var rows = msg.payload.list || [];

// Status mapping: NocoDB → UMH event type
var statusMap = {
    "Nieuw": "order.created",
    "Bezig": "order.progress",
    "Klaar": "order.closed"
};

var messages = rows.map(function(r) {
    var eventType = statusMap[r.status] || "order.created";
    var payload = {
        event_type: eventType,
        line_id: r.asset || "onbekend",
        data: {
            id: r.order_nr,
            product_id: r.product || r.order_nr,
            planned_qty: r.qty || 0,
            customer: r.customer || null,
            priority: r.priority || null,
            due_date: r.due_date || null
        }
    };

    // Voor progress/closed: voeg quantity velden toe
    if (eventType === "order.progress" || eventType === "order.closed") {
        payload.data.good_qty = r.qty_completed || 0;
        payload.data.scrap_qty = r.qty_scrap || 0;
    }

    return {
        payload: payload,
        headers: { "Content-Type": "application/json" }
    };
});

node.status({text: rows.length + " werkorders → UNS"});
return [messages];
